return items.map((item, idx) => {
  const row = item.json;
  return {
    json: {
      ticket_id: String(row.ticket_id || row.id || `csv-${idx}`),
      cliente: String(row.cliente_nome || row.cliente || 'Cliente sem nome'),
      canal: String(row.canal || 'outro'),
      mensagens: String(row.mensagem || row.texto || row.descricao || ''),
      tecnico: String(row.tecnico || 'Importacao CSV'),
      data_evento: String(row.data_evento || row.created_at || new Date().toISOString()),
      metadata: {
        sourceSystem: String($env.SOURCE_SYSTEM || 'file'),
        sourceEntityId: String(row.ticket_id || row.id || idx),
        tenantId: String($env.TENANT_ID || 'default'),
        ingestionId: `file-${Date.now()}-${idx}`
      }
    }
  };
});
